import { describe, expect, it, vi } from 'vitest'
import { render, screen } from '@testing-library/react'
import React from 'react'
import { AxisRenderer } from '@/ui/web/exerciserenderer/blocks/AxisRenderer'
import type { AxisSpecV1 } from '@/infra/contracts/graphics/axis.v1'

// Mock the dynamic import of JSXGraphBoard
vi.mock('@/ui/web/exerciserenderer/graphics/JSXGraphBoard', () => ({
  JSXGraphBoard: vi.fn(() => <div data-testid="jsxgraph-board">Mock Board</div>),
}))

// Mock the renderAxisSpec function
vi.mock('@/ui/web/exerciserenderer/graphics/axisElements', () => ({
  renderAxisSpec: vi.fn(),
}))

describe('AxisRenderer Display Size Prop', () => {
  // Helper to create a minimal valid axis spec
  const createTestSpec = (): AxisSpecV1 => ({
    kind: 'cartesian',
    units: 1,
    grid: { enabled: true },
    axes: {
      showNumbers: true,
      showLabels: true,
      ticks: 1,
      labels: { x: 'x', y: 'y' },
      origin: { x: 0, y: 0 },
    },
    viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
    elements: { points: [], graphs: [] },
  })

  describe('3.1: AxisRenderer accepts displaySize prop', () => {
    it('given displaySize="small", when rendered, then component should render without error', () => {
      const renderFn = () => {
        render(
          <AxisRenderer
            blockId="test-axis-1"
            spec={createTestSpec()}
            displaySize="small"
          />
        )
      }
      expect(renderFn).not.toThrow()
    })

    it('given displaySize="medium", when rendered, then component should render without error', () => {
      const renderFn = () => {
        render(
          <AxisRenderer
            blockId="test-axis-1"
            spec={createTestSpec()}
            displaySize="medium"
          />
        )
      }
      expect(renderFn).not.toThrow()
    })

    it('given displaySize="large", when rendered, then component should render without error', () => {
      const renderFn = () => {
        render(
          <AxisRenderer
            blockId="test-axis-1"
            spec={createTestSpec()}
            displaySize="large"
          />
        )
      }
      expect(renderFn).not.toThrow()
    })

    it('given displaySize="full", when rendered, then component should render without error', () => {
      const renderFn = () => {
        render(
          <AxisRenderer
            blockId="test-axis-1"
            spec={createTestSpec()}
            displaySize="full"
          />
        )
      }
      expect(renderFn).not.toThrow()
    })
  })

  describe('3.2: AxisRenderer defaults to displaySize="full" when prop not provided', () => {
    it('given no displaySize prop, when rendered, then component should render with full width', () => {
      const renderFn = () => {
        render(<AxisRenderer blockId="test-axis-1" spec={createTestSpec()} />)
      }
      expect(renderFn).not.toThrow()
    })
  })

  describe('3.3: AxisRenderer exports DisplaySize type', () => {
    it('should export DisplaySize type from the module', () => {
      // This test verifies that the DisplaySize type is exported
      // The import itself will fail if the type doesn't exist
      expect(true).toBe(true) // Placeholder - type checking happens at compile time
    })
  })

  describe('3.4: AxisRenderer renders container element for responsive sizing', () => {
    it('given displaySize="medium", when rendered, then container element should exist', () => {
      render(
        <AxisRenderer
          blockId="test-axis-1"
          spec={createTestSpec()}
          displaySize="medium"
        />
      )
      // The container should have the justify-center class from the renderer
      const container = screen.getByTestId('jsxgraph-board').parentElement
      expect(container).toBeInTheDocument()
    })
  })
})

