/**
 * Unit Test: AxisEditor Display Size Dropdown
 *
 * Tests that the AxisEditor component renders a Display Size dropdown.
 * This is part of the fix for issue #813 (control graph display size in exercises).
 */

import '@testing-library/jest-dom'
import { describe, expect, it, vi } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import React from 'react'
import { AxisEditor } from '@/ui/admin/ExerciseContentEditor/editors/AxisEditor'
import type { QuestionAxisBlock } from '@/server/payload/collections/Exercises/types'
import type { AxisSpecV1 } from '@/infra/contracts/graphics/axis.v1'

describe('AxisEditor Display Size Dropdown', () => {
  // Helper to create a minimal valid axis block
  const createTestBlock = (displaySize?: 'small' | 'medium' | 'large' | 'full'): QuestionAxisBlock => ({
    id: 'test-axis-1',
    type: 'question_axis',
    prompt: {
      type: 'rich_text',
      format: 'md-math-v1',
      value: 'Test question about the graph',
      mediaIds: [],
    },
    axis: {
      kind: 'cartesian',
      units: 1,
      grid: { enabled: true },
      axes: {
        showNumbers: true,
        showLabels: true,
        ticks: 1,
        labels: { x: 'x', y: 'y' },
        origin: { x: 0, y: 0 },
      },
      viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
      elements: { points: [], graphs: [] },
    } as AxisSpecV1,
    displaySize,
  })

  describe('2.1: AxisEditor renders Display Size dropdown', () => {
    it('given an axis block without displaySize, when rendered, then a select element with label "Display Size" should exist', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock()} onChange={mockOnChange} />)

      const selectElement = screen.getByLabelText(/display size/i)
      expect(selectElement).toBeInTheDocument()
    })

    it('given an axis block with displaySize="medium", when rendered, then the select should have value "medium"', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock('medium')} onChange={mockOnChange} />)

      const selectElement = screen.getByLabelText(/display size/i) as HTMLSelectElement
      expect(selectElement.value).toBe('medium')
    })
  })

  describe('2.2: AxisEditor displays all four size options', () => {
    it('given an axis block, when rendered, then all four options should be available', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock()} onChange={mockOnChange} />)

      const selectElement = screen.getByLabelText(/display size/i)

      expect(screen.getByRole('option', { name: /small.*33/i })).toBeInTheDocument()
      expect(screen.getByRole('option', { name: /medium.*50/i })).toBeInTheDocument()
      expect(screen.getByRole('option', { name: /large.*75/i })).toBeInTheDocument()
      expect(screen.getByRole('option', { name: /full.*100/i })).toBeInTheDocument()
    })
  })

  describe('2.3: AxisEditor calls onChange when displaySize is changed', () => {
    it('given an axis block with displaySize="medium", when user selects "large", then onChange should be called with displaySize="large"', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock('medium')} onChange={mockOnChange} />)

      const selectElement = screen.getByLabelText(/display size/i)
      fireEvent.change(selectElement, { target: { value: 'large' } })

      expect(mockOnChange).toHaveBeenCalledTimes(1)
      const updatedBlock = mockOnChange.mock.calls[0][0] as QuestionAxisBlock
      expect(updatedBlock.displaySize).toBe('large')
    })

    it('given an axis block without displaySize, when user selects "small", then onChange should be called with displaySize="small"', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock()} onChange={mockOnChange} />)

      const selectElement = screen.getByLabelText(/display size/i)
      fireEvent.change(selectElement, { target: { value: 'small' } })

      expect(mockOnChange).toHaveBeenCalledTimes(1)
      const updatedBlock = mockOnChange.mock.calls[0][0] as QuestionAxisBlock
      expect(updatedBlock.displaySize).toBe('small')
    })
  })

  describe('2.4: AxisEditor Display Size dropdown appears before Prompt section', () => {
    it('given an axis block, when rendered, then the Display Size dropdown should appear before the Prompt label', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock()} onChange={mockOnChange} />)

      const displaySizeLabel = screen.getByText(/display size/i)
      const promptLabel = screen.getByText(/prompt/i)

      // Check that Display Size comes before Prompt in the DOM
      expect(displaySizeLabel.compareDocumentPosition(promptLabel)).toBe(Node.DOCUMENT_POSITION_FOLLOWING)
    })
  })
})

