      expect(screen.queryByRole('option', { name: /full.*100/i })).toBeTruthy()
    })
  })

  describe('2.3: AxisEditor calls onChange when displaySize is changed', () => {
    it('given an axis block with displaySize="medium", when user selects "large", then onChange should be called with displaySize="large"', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock('medium')} onChange={mockOnChange} />)

      const selectElement = screen.queryByLabelText(/display size/i) as HTMLSelectElement | null
      expect(selectElement).toBeTruthy()

      if (selectElement) {
        fireEvent.change(selectElement, { target: { value: 'large' } })
        expect(mockOnChange).toHaveBeenCalledTimes(1)
        const updatedBlock = mockOnChange.mock.calls[0][0] as QuestionAxisBlock
        expect(updatedBlock.displaySize).toBe('large')
      }
    })
  })

  describe('2.4: AxisEditor Display Size dropdown appears before Prompt section', () => {
    it('given an axis block, when rendered, then the Display Size dropdown should appear before the Prompt label', () => {
      const mockOnChange = vi.fn()
      render(<AxisEditor block={createTestBlock()} onChange={mockOnChange} />)

      const displaySizeLabel = screen.queryByText(/display size/i)
      const promptLabel = screen.queryByText(/prompt/i)

      expect(displaySizeLabel).toBeTruthy()
      expect(promptLabel).toBeTruthy()

      if (displaySizeLabel && promptLabel) {
        expect(displaySizeLabel.compareDocumentPosition(promptLabel)).toBe(
          Node.DOCUMENT_POSITION_FOLLOWING,
        )
      }
    })
  })
})
